function fb(a, b) { if (a) { return a; } return b; }
var files = [];
var resp = fb($.steps.listDriveFiles.response, {});
var rawFiles = fb(resp.files, []);

rawFiles.forEach(function(f, i) {
  files.push({
    index: i + 1,
    name: fb(f.name, 'Untitled'),
    mimeType: fb(f.mimeType, 'unknown'),
    modified: fb(f.modifiedTime, 'unknown'),
    size: fb(f.size, 'unknown'),
    link: fb(f.webViewLink, '')
  });
});

var fileList = '';
files.forEach(function(f) {
  fileList += f.index + '. ' + f.name + ' (' + f.mimeType + ')\n';
  fileList += '   Modified: ' + f.modified + ' | Size: ' + f.size + ' bytes\n';
  fileList += '   Link: ' + f.link + '\n\n';
});

return { files: files, fileList: fileList, fileCount: files.length };

var data = $.steps.compileFileList.output;

var prompt = 'You are a document analyst. Given the following Google Drive file listing, provide a structured summary and organization of the files.\n\n';
prompt += 'FILE LISTING (' + data.fileCount + ' files):\n\n';
prompt += data.fileList + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Categorize files by type and purpose\n';
prompt += '- Identify the most recently modified files\n';
prompt += '- Suggest which files might need attention or review\n';
prompt += '- Note any patterns in file naming or organization\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "2-3 sentence overview of the Drive contents",\n';
prompt += '  "categories": [{ "name": "category", "files": ["file names"], "description": "what these files contain" }],\n';
prompt += '  "recentlyModified": [{ "name": "file name", "modified": "date", "note": "why it might be relevant" }],\n';
prompt += '  "actionItems": ["suggested action 1", "suggested action 2"],\n';
prompt += '  "totalFiles": 0\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiAnalysis.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, categories: [], totalFiles: $.steps.compileFileList.output.fileCount }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var fileCount = $.steps.compileFileList.output.fileCount;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':file_folder: Google Drive Summary — ' + fileCount + ' files', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fb(ai.summary, fileCount) + ' file(s) analyzed.' } });
blocks.push({ type: 'divider' });

var categories = fb(ai.categories, []);
categories.forEach(function(cat) {
  var catText = '*' + cat.name + '*\n';
  catText += cat.description + '\n';
  var catFiles = fb(cat.files, []);
  catFiles.forEach(function(f) { catText += '  - ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText } });
});

var recent = fb(ai.recentlyModified, []);
if (recent.length > 0) {
  blocks.push({ type: 'divider' });
  var recentText = '*:clock1: Recently Modified*\n';
  recent.forEach(function(r) {
    recentText += '- *' + r.name + '* (' + r.modified + '): ' + (fb(r.note, '')) + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recentText } });
}

var actions = fb(ai.actionItems, []);
if (actions.length > 0) {
  blocks.push({ type: 'divider' });
  var actionText = '*:pushpin: Suggested Actions*\n';
  actions.forEach(function(a, i) { actionText += (i + 1) + '. ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: actionText } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Drive + Claude AI + One CLI' }] });

var fallback = 'Google Drive Summary: ' + fileCount + ' files analyzed';
return { blocks: blocks, fallback: fallback };
